import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as r,o as s,X as n}from"./chunks/vendor-vueuse.XPft87tp.js";const u=JSON.parse('{"title":"JS 设计成单线程的目的","description":"","frontmatter":{},"headers":[],"relativePath":"basics/js-single-thread.md","filePath":"basics/js-single-thread.md","lastUpdated":1784884957000}'),t={name:"basics/js-single-thread.md"};function o(i,a,l,p,d,c){return s(),r("div",null,a[0]||(a[0]=[n(`<h1 id="js-设计成单线程的目的" tabindex="-1">JS 设计成单线程的目的 <a class="header-anchor" href="#js-设计成单线程的目的" aria-label="Permalink to &quot;JS 设计成单线程的目的&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>JavaScript 从诞生之初就是单线程的，这是设计选择，不是局限。想想它最初是干什么的——操作 DOM、响应用户交互。多线程去抢同一个 DOM 节点？光想想就头疼。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="为什么是单线程" tabindex="-1">为什么是单线程 <a class="header-anchor" href="#为什么是单线程" aria-label="Permalink to &quot;为什么是单线程&quot;">​</a></h3><p>浏览器里 JS 的主要工作是：用户点了个按钮 → 改个 DOM → 绑个事件。如果是多线程，两个线程同时操作同一个 DOM 节点，浏览器不知道该听谁的，页面就直接乱套了。</p><p>你可以这样理解：多线程操作 DOM 就像两个人同时抢方向盘——不开飞的几率是零。</p><h3 id="怎么处理耗时任务" tabindex="-1">怎么处理耗时任务 <a class="header-anchor" href="#怎么处理耗时任务" aria-label="Permalink to &quot;怎么处理耗时任务&quot;">​</a></h3><p>单线程有一个致命问题：某段代码卡住了，整个页面就动不了。解决方案是<strong>异步</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span>主线程：执行同步代码 → 遇到异步任务丢给 Web API → 继续往下走</span></span>
<span class="line"><span>Web API：定时器/网络请求完成后 → 回调塞进任务队列</span></span>
<span class="line"><span>事件循环：主线程空了 → 从队列里取回调执行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这就是事件循环（Event Loop）的雏形。JS 本身还是单线程在跑，但浏览器是多线程的——定时器、网络请求都交给浏览器的其他线程处理，处理完把回调塞回来。</p><h3 id="worker-线程" tabindex="-1">Worker 线程 <a class="header-anchor" href="#worker-线程" aria-label="Permalink to &quot;Worker 线程&quot;">​</a></h3><p>后来 HTML5 加了 Web Worker，可以开真正的多线程。但 Worker 不能操作 DOM，本质上是给主线程当苦力用的——主线程管 UI，Worker 管计算，井水不犯河水。</p><h2 id="实战场景" tabindex="-1">实战场景 <a class="header-anchor" href="#实战场景" aria-label="Permalink to &quot;实战场景&quot;">​</a></h2><p>写复杂动画或者大量数据处理时，如果不拆任务，页面就会卡。常见的做法是把大任务拆成小份用 <code>requestAnimationFrame</code> 或者丢给 Worker。React 的 Concurrent Mode 本质上也是在利用事件循环的机制，把渲染任务拆成可中断的小块。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>JS 单线程是为了省掉 DOM 操作的锁和同步问题。异步 + 事件循环是它的并发方案，Worker 是它的多线程补丁。</p>`,17)]))}const m=e(t,[["render",o]]);export{u as __pageData,m as default};
